module top_module(input clk,input rst,input in,output out);reg [1:0] state, nextstate; 
  parameter [1:0] Zero = 2'b00, Edge = 2'b01, One=2'b10 ; 
  always @ (*) 
  case (state) 
  Zero: if(in) nextstate = Edge; 
  else nextstate = Zero; 
  Edge: if (in) nextstate = One; 
  else nextstate = Zero; 
  One: if(in) nextstate= One; 
  else nextstate= Zero; 
  default: 
  nextstate = 2'bx; 
  endcase 
  always @ (posedge clk or posedge rst) 
  begin 
  if (rst) state <=Zero; 
  else state <= nextstate; 
  end 
    wire _n01 = state[0] ^ Edge[0];
  wire _n02 = state[1] ^ Edge[1];
  wire _n03 = state[2] ^ Edge[2];
  wire _n04 = state[3] ^ Edge[3];
  assign out = ~_n01 & ~_n02 & ~_n03 & ~_n04; 
 endmodule
